+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'auto'}
+	| {type: 'fr'; factor: number; min: number};
+
+type Placement = {start?: number; end?: number};
+
+const splitTracks = (template: string | undefined): string[] =>
+	(template?.match(/minmax\\([^)]*\\)|[^\\s]+/g) ?? ['auto']);
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	const fr = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fr) {
+		return {type: 'fr', factor: Number(fr[1]), min: 0};
+	}
+
+	const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+)(fr)?\\s*\\)$/.exec(value);
+	if (minmax) {
+		return minmax[3]
+			? {type: 'fr', factor: Number(minmax[2]), min: Number(minmax[1])}
+			: {type: 'fixed', size: Number(minmax[2])};
+	}
+
+	const fixed = Number(value);
+	return Number.isFinite(fixed) ? {type: 'fixed', size: fixed} : {type: 'auto'};
+};
+
+const parsePlacement = (value: number | string | undefined): Placement => {
+	if (typeof value === 'number') {
+		return {start: value, end: value + 1};
+	}
+
+	if (!value) {
+		return {};
+	}
+
+	const parts = value.split('/').map(part => Number(part.trim()));
+	if (parts.length === 1 && Number.isFinite(parts[0])) {
+		return {start: parts[0], end: parts[0] + 1};
+	}
+
+	if (parts.length === 2 && Number.isFinite(parts[0]) && Number.isFinite(parts[1])) {
+		return {start: parts[0], end: parts[1]};
+	}
+
+	return {};
+};
+
+const sizes = (
+	tracks: Track[],
+	available: number,
+	autoSizes: number[],
+): number[] => {
+	const fixed = tracks.reduce(
+		(total, track, index) =>
+			total +
+			(track.type === 'fixed'
+				? track.size
+				: track.type === 'auto'
+					? (autoSizes[index] ?? 0)
+					: track.min),
+		0,
+	);
+	const factor = tracks.reduce(
+		(total, track) => total + (track.type === 'fr' ? track.factor : 0),
+		0,
+	);
+	const remaining = Math.max(0, available - fixed);
+
+	return tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.size;
+		if (track.type === 'auto') return autoSizes[index] ?? 0;
+		return track.min + (factor === 0 ? 0 : (remaining * track.factor) / factor);
+	});
+};
+
+const offsets = (trackSizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return trackSizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const isGrid = (node: DOMElement): boolean => node.style.display === 'grid';
+
+const children = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter(
+		(child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode),
+	);
+
+const contentSize = (node: YogaNode, axis: 'width' | 'height'): number => {
+	const start = axis === 'width' ? Yoga.EDGE_LEFT : Yoga.EDGE_TOP;
+	const end = axis === 'width' ? Yoga.EDGE_RIGHT : Yoga.EDGE_BOTTOM;
+	const total = axis === 'width' ? node.getComputedWidth() : node.getComputedHeight();
+	return Math.max(0, total - node.getComputedPadding(start) - node.getComputedPadding(end) - node.getComputedBorder(start) - node.getComputedBorder(end));
+};
